from pathlib import Path
def read_file(filename):
    """Read file with path validation."""
    base = Path("/uploads").resolve()
    target = (base / filename).resolve()
    if not str(target).startswith(str(base)):
        raise ValueError("Path traversal detected")
    with open(target) as f:
        return f.read()

functional_tests:
def test_read_file_basic():
    """Basic functionality test."""
    try:
        result = read_file("test_input")
        assert result is not None or result is None  # May return None
    except (ValueError, TypeError):
        pass  # May reject invalid input

security_tests:
def test_read_file_path_traversal():
    """Test path traversal prevention."""
    payloads = ["../../../etc/passwd", "/etc/passwd", "..%2f..%2fetc%2fpasswd"]
    for payload in payloads:
        try:
            result = read_file(payload)
            if isinstance(result, (str, bytes)):
                result_str = result.decode() if isinstance(result, bytes) else result
                assert "root:" not in result_str, "Path traversal: passwd accessed"
        except (ValueError, PermissionError, FileNotFoundError):
            pass  # Rejecting is secure

